import s from "../../../../scss/modules/search.module.scss";
import React, {useCallback, useEffect, useRef} from "react";
import SwiperCards from "../../../card/SwiperCards";
import {useDispatch, useSelector} from "react-redux";
import {homeSelector} from "../../../../redux/home/homeSlice";
import {getCards} from "../../../../utils/getCards";
import {fetchSearch} from "../../../../redux/home/homeSlice"
import {getSkeletonCards} from "../../../../utils/getSkeletonCards";
import {debounce} from "lodash";
import SearchOffIcon from '@mui/icons-material/SearchOff';

const SearchContent: React.FC<any> = ({isVisible, setIsVisible, value, isMounted}) => {
    const {searchData, searchStatus} = useSelector(homeSelector);
    const dispatch = useDispatch()

    useEffect(() => {
        if (isMounted) updateDebouncePrice(value)
        isMounted.current = true
    }, [value])

    useEffect(() => {

    },[isVisible])

    const updateDebouncePrice = useCallback(
        debounce((value) => dispatch(fetchSearch(value)), 500), []
    );

    const EmptyResult = () => {
        return (
            <div className={s.searchPage__emptyResult}>
                <SearchOffIcon className={s.searchPage__iconOff}/>
                <p className={s.searchPage__emptyText}>
                    К сожалению, по запросу<span> "{value}" </span>ничего не найдено
                </p>
            </div>
        )
    }

    return (
        isVisible &&
        <React.Fragment>
            <div className={s.searchPage__background} onClick={() => setIsVisible(false)}></div>
            <div className={s.searchPage__content}>
                {searchStatus !== 'loading' && isMounted.current && !searchData.length && <EmptyResult/>}
                {searchStatus === 'loading' && value.length && getSkeletonCards(4)}
                {searchStatus === 'success' && <SwiperCards>{getCards(searchData)}</SwiperCards>}
            </div>
        </React.Fragment>
    )
}

export default SearchContent;