import React, {useEffect, useRef, useState} from "react";
import Box from "@mui/material/Box";
import SearchOutlinedIcon from "@mui/icons-material/SearchOutlined";
import {InputBase, IconButton} from "@mui/material";
import s from "../../../../scss/modules/search.module.scss";
import SearchContent from "./SearchContent";
import KeyboardBackspaceIcon from '@mui/icons-material/KeyboardBackspace';
import {resetSearchItems} from "../../../../redux/home/homeSlice";
import {useDispatch} from "react-redux";

const Search: React.FC = () => {
    const [isVisible, setIsVisible] = useState<boolean>(false);
    const [searchValue, setSearchValue] = useState<string>("");
    const isMounted = useRef(false)
    const dispatch = useDispatch();

    useEffect(() => {
        dispatch(resetSearchItems())
        if (!isVisible) {
            isMounted.current = false
            setSearchValue("")
        }
    },[isVisible])

    return (
        <div className={s.searchPage}>
            <SearchContent
                isVisible={isVisible}
                value={searchValue}
                setIsVisible={setIsVisible}
                isMounted={isMounted}
            />
            <Box
                className={s.search}
                style={{
                    transform: isVisible ? "scale(1.1)" : "scale(1)",
                    position: isVisible ? "fixed" : "static",
                    top: isVisible ? 78 : 0,
                }}
            >
                {
                    isVisible &&
                    <IconButton
                        className={s.search__close}
                        aria-label="delete"
                        size="large"
                        onClick={() => setIsVisible(false)}
                    >
                        <KeyboardBackspaceIcon fontSize="inherit" sx={{fill: "#fff"}}/>
                    </IconButton>
                }
                <Box className={s.search__backgroundIcon}></Box>
                <SearchOutlinedIcon
                    className={s.search__searchIcon}
                    sx={{color: "#fff", mr: 1, ml: 1, width: 22, height: 22}}
                />
                <InputBase
                    sx={{
                        ml: 1,
                        flex: 1,
                        minWidth: '20em',
                        paddingRight: '12px',
                        color: '#414141',
                        fontSize: '14px',
                    }}
                    value={searchValue}
                    placeholder="Поиск по сайту..."
                    type="search"
                    onChange={(evt) => setSearchValue(evt.target.value)}
                    onFocus={() => setIsVisible(true)}
                />
            </Box>
        </div>
    );
}

export default Search;